"""
evaluate.py
===========
Automated evaluation pipeline for the study:
  "A Comparative Analysis of Code Quality Generated by ChatGPT (GPT-4o),
   Claude (3.5 Sonnet), and GitHub Copilot Using Software Engineering Metrics"

This script:
  1. Loads raw_outputs.json
  2. Executes unit tests per task per model (functional correctness)
  3. Computes static analysis metrics (readability via pylint, maintainability via radon)
  4. Measures execution runtime via timeit
  5. Writes results/metrics.csv and results/cqs_results.csv

Dependencies:
    pip install pytest radon pylint

Usage:
    python scripts/evaluate.py
    python scripts/evaluate.py --verbose
"""

import argparse
import csv
import importlib
import importlib.util
import json
import math
import os
