# ─── Path configuration ────────────────────────────────────────────────────
ROOT        = Path(__file__).resolve().parent.parent
DATA_FILE   = ROOT / "data" / "raw_outputs.json"
RESULTS_DIR = ROOT / "results"
METRICS_CSV = RESULTS_DIR / "metrics.csv"
CQS_CSV     = RESULTS_DIR / "cqs_results.csv"
SOL_DIR     = ROOT / "scripts" / "solutions"

RESULTS_DIR.mkdir(exist_ok=True)
SOL_DIR.mkdir(exist_ok=True)

MODELS = ["ChatGPT", "Claude", "GitHub_Copilot"]

# ─── Task-specific timeit input factories ─────────────────────────────────
# Each entry maps task_id -> (setup_code, stmt, number_of_iterations)
