# ─── Big-O ground truth (manually determined by researchers) ──────────────
BIG_O = {
    "T01": {"ChatGPT": "O(sqrt(n))", "Claude": "O(sqrt(n))", "GitHub_Copilot": "O(sqrt(n))"},
    "T02": {"ChatGPT": "O(n)",       "Claude": "O(n)",        "GitHub_Copilot": "O(n)"},
    "T03": {"ChatGPT": "O(1)",       "Claude": "O(1)",        "GitHub_Copilot": "O(1)"},
    "T04": {"ChatGPT": "O(log n)",   "Claude": "O(log n)",    "GitHub_Copilot": "O(log n)"},
    "T05": {"ChatGPT": "O(n)",       "Claude": "O(n)",        "GitHub_Copilot": "O(n)"},
    "T06": {"ChatGPT": "O(1) per op","Claude": "O(1) per op", "GitHub_Copilot": "O(1) per op"},
    "T07": {"ChatGPT": "O(V+E)",     "Claude": "O(V+E)",      "GitHub_Copilot": "O(V+E)"},
    "T08": {"ChatGPT": "O(n log n)", "Claude": "O(n log n)",  "GitHub_Copilot": "O(n log n)"},
    "T09": {"ChatGPT": "O(1) per op","Claude": "O(1) per op", "GitHub_Copilot": "O(1) per op"},
    "T10": {"ChatGPT": "O(n) get/put","Claude": "O(1) avg",   "GitHub_Copilot": "O(n) get/put"},
}


def load_raw_outputs():
    with open(DATA_FILE) as f:
        return json.load(f)


def extract_solution(task_id, model, code):
    """Write code to a temp module and return the module object."""
    task_sol_dir = SOL_DIR / task_id
    task_sol_dir.mkdir(exist_ok=True)
    sol_file = task_sol_dir / f"{model}.py"
    sol_file.write_text(code, encoding="utf-8")

    spec = importlib.util.spec_from_file_location(f"{task_id}_{model}", sol_file)
    mod = importlib.util.module_from_spec(spec)
    try:
        spec.loader.exec_module(mod)
    except Exception as e:
        return None, str(e)
    return mod, None


def run_unit_tests(task_id, model, code, verbose=False):
    """
    Execute the unit tests for a given task/model combination.
    Returns (passed, total, error_msg).
    """
    task_sol_dir = SOL_DIR / task_id
    task_sol_dir.mkdir(exist_ok=True)
    # Write the solution so the test fixture can import it
    sol_file = task_sol_dir / "solution.py"
    sol_file.write_text(code, encoding="utf-8")

    # Run pytest programmatically via subprocess to isolate namespace
    test_file = ROOT / "tests" / "test_cases.py"
    class_name = f"TestT{task_id[1:]}_"

    # Find the matching test class name
    class_map = {
        "T01": "TestT01_IsPrime",
        "T02": "TestT02_ReverseString",
        "T03": "TestT03_ConvertTemperature",
        "T04": "TestT04_BinarySearch",
        "T05": "TestT05_AggregateCSV",
        "T06": "TestT06_Stack",
        "T07": "TestT07_BFS",
        "T08": "TestT08_MergeSort",
        "T09": "TestT09_InventoryManager",
        "T10": "TestT10_LRUCache",
    }
    target_class = class_map.get(task_id, "")

    cmd = [
        sys.executable, "-m", "pytest",
        f"{test_file}::{target_class}",
        "--tb=no", "-q",
        f"--rootdir={ROOT}",
    ]
    env = os.environ.copy()
    env["PYTHONPATH"] = str(ROOT)

    result = subprocess.run(cmd, capture_output=True, text=True, env=env)
    output = result.stdout + result.stderr

    # Parse pytest output: "X passed, Y failed" or "X passed"
    passed = total = 0
    for line in output.splitlines():
        if "passed" in line or "failed" in line or "error" in line:
            import re
            nums = re.findall(r'(\d+)\s+(passed|failed|error)', line)
            for n, status in nums:
                total += int(n)
                if status == "passed":
                    passed += int(n)

    if verbose:
        print(f"  [TEST] {task_id}/{model}: {passed}/{total}")
        if result.returncode not in (0, 1):
            print(f"    STDERR: {result.stderr[:300]}")

    error = None if result.returncode in (0, 1) else result.stderr[:200]
    return passed, total, error


def compute_pylint_score(code):
    """Run pylint on code string and return score (0.0–10.0)."""
    with tempfile.NamedTemporaryFile(mode='w', suffix='.py',
                                     delete=False, encoding='utf-8') as f:
        f.write(code)
        tmp_path = f.name
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pylint", tmp_path,
             "--score=yes", "--disable=all",
             "--enable=C,W,E,R",
             "--output-format=text"],
            capture_output=True, text=True
        )
        output = result.stdout + result.stderr
        import re
        match = re.search(r'Your code has been rated at\s+([-\d.]+)/10', output)
        if match:
            score = float(match.group(1))
            return max(0.0, min(10.0, score))
    except Exception:
        pass
    finally:
        os.unlink(tmp_path)
    return 5.0  # fallback neutral score


def compute_cyclomatic_complexity(code):
    """Use radon to compute mean Cyclomatic Complexity."""
    with tempfile.NamedTemporaryFile(mode='w', suffix='.py',
                                     delete=False, encoding='utf-8') as f:
        f.write(code)
        tmp_path = f.name
    try:
        result = subprocess.run(
            [sys.executable, "-m", "radon", "cc", tmp_path, "-s", "-a"],
            capture_output=True, text=True
        )
        output = result.stdout
        import re
        match = re.search(r'Average complexity:\s+\w+\s*\(([\d.]+)\)', output)
        if match:
            return float(match.group(1))
        # Fallback: parse individual function blocks
        scores = re.findall(r'\(([A-F])\s+([\d.]+)\)', output)
        if scores:
            vals = [float(v) for _, v in scores]
            return round(sum(vals) / len(vals), 2)
    except Exception:
        pass
    finally:
        os.unlink(tmp_path)
    return 1.0  # no complexity found = simple


def measure_runtime_ms(task_id, model, code, iterations):
    """Execute the code with timeit and return mean runtime in ms."""
    config = TIMEIT_CONFIGS.get(task_id, {})
    stmt = config.get("stmt")

    if stmt is None or task_id == "T05":
        # File I/O task: create temp CSV and measure
        import csv as _csv
        with tempfile.NamedTemporaryFile(mode='w', suffix='.csv',
                                         delete=False, newline='') as f:
            writer = _csv.writer(f)
            writer.writerow(['group', 'value'])
            for i in range(200):
                writer.writerow([f'group_{i % 5}', float(i * 1.5)])
            tmp_csv = f.name
        try:
            setup = code + f"\n_csv_path = r'{tmp_csv}'"
            t = timeit.timeit(
                stmt="aggregate_csv(_csv_path)",
                setup=setup,
                number=100
            )
            return round((t / 100) * 1000, 4)
        except Exception:
            return None
        finally:
            os.unlink(tmp_csv)

    setup_extra = config.get("setup_extra", "")
    setup = code + ("\n" + setup_extra if setup_extra else "")

    try:
        t = timeit.timeit(stmt=stmt, setup=setup, number=iterations)
        mean_ms = (t / iterations) * 1000
        return round(mean_ms, 6)
    except Exception as e:
        return None


def normalize_inverted(values):
    """Min-max normalize where lower raw value = higher normalized score."""
    valid = [v for v in values if v is not None]
    if not valid:
        return [None] * len(values)
    mn, mx = min(valid), max(valid)
    if mx == mn:
        return [1.0 if v is not None else None for v in values]
    return [
        round(1.0 - (v - mn) / (mx - mn), 4) if v is not None else None
        for v in values
    ]


def normalize(values):
    """Min-max normalize where higher raw value = higher normalized score."""
    valid = [v for v in values if v is not None]
    if not valid:
        return [None] * len(values)
    mn, mx = min(valid), max(valid)
    if mx == mn:
        return [1.0 if v is not None else None for v in values]
    return [
        round((v - mn) / (mx - mn), 4) if v is not None else None
        for v in values
    ]


def main(verbose=False):
    print("=" * 60)
    print("AI Code Quality Evaluation Pipeline")
    print("=" * 60)

    data = load_raw_outputs()
    tasks = data["tasks"]

    # ── Collect raw measurements ──────────────────────────────────────────
    records = []  # list of dicts, one per (task, model)

    for task in tasks:
        task_id   = task["task_id"]
        task_name = task["task_name"]
        iters     = TIMEIT_CONFIGS.get(task_id, {}).get("iterations", 1000)

        print(f"\n[{task_id}] {task_name}")

        for model in MODELS:
            code = task["outputs"][model]["code"]
            print(f"  Processing: {model} ...", end=" ", flush=True)

            # 1. Functional correctness
            passed, total, err = run_unit_tests(task_id, model, code, verbose)
            pass_rate = round((passed / total) * 100, 2) if total > 0 else 0.0

            # 2. Pylint score
            pylint_score = compute_pylint_score(code)
            pylint_norm  = round(pylint_score / 10.0, 4)

            # 3. Cyclomatic complexity
            cc = compute_cyclomatic_complexity(code)

            # 4. Runtime
            runtime_ms = measure_runtime_ms(task_id, model, code, iters)

            # 5. Big-O (manually determined)
            big_o = BIG_O.get(task_id, {}).get(model, "N/A")

            records.append({
                "task_id":       task_id,
                "task_name":     task_name,
                "model":         model,
                "pass_rate":     pass_rate,
                "passed_tests":  passed,
                "total_tests":   total,
                "pylint_score":  pylint_score,
                "pylint_norm":   pylint_norm,
                "cc":            cc,
                "runtime_ms":    runtime_ms,
                "big_o":         big_o,
            })
            print(f"pass={pass_rate:.0f}%  pylint={pylint_score:.1f}  "
                  f"CC={cc:.1f}  rt={runtime_ms}ms")

    # ── Normalize across all tasks for each model ─────────────────────────
    # For CQS we compute per-task normalization across 3 models, then average

    task_ids = [t["task_id"] for t in tasks]

    # Add normalized columns to records
    for rec in records:
        rec["fc_norm"]  = round(rec["pass_rate"] / 100.0, 4)
        rec["cr_norm"]  = rec["pylint_norm"]  # placeholder; rubric added manually

    # CC normalization (inverted, per task)
    for tid in task_ids:
        cc_vals = [r["cc"] for r in records if r["task_id"] == tid]
        cc_norms = normalize_inverted(cc_vals)
        for r, n in zip([r for r in records if r["task_id"] == tid], cc_norms):
            r["cc_norm"] = n

    # Runtime normalization (inverted, per task)
    for tid in task_ids:
        rt_vals = [r["runtime_ms"] for r in records if r["task_id"] == tid]
        rt_norms = normalize_inverted(rt_vals)
        for r, n in zip([r for r in records if r["task_id"] == tid], rt_norms):
            r["rt_norm"] = n

    # ── Write metrics.csv ─────────────────────────────────────────────────
    fieldnames = [
        "task_id", "task_name", "model",
        "pass_rate", "passed_tests", "total_tests",
        "fc_norm",
        "pylint_score", "pylint_norm", "cr_norm",
        "big_o",
        "runtime_ms", "rt_norm",
        "cc", "cc_norm",
    ]

    with open(METRICS_CSV, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=fieldnames, extrasaction="ignore")
        writer.writeheader()
        writer.writerows(records)

    print(f"\n[✓] Metrics written → {METRICS_CSV}")

    # ── Compute CQS per model ─────────────────────────────────────────────
    cqs_rows = []
    for model in MODELS:
        model_recs = [r for r in records if r["model"] == model]
        n = len(model_recs)

        fc_mean  = round(sum(r["fc_norm"]         for r in model_recs) / n, 4)
        cr_mean  = round(sum(r["pylint_norm"]      for r in model_recs) / n, 4)
        ef_mean  = round(sum(r["rt_norm"] or 0     for r in model_recs) / n, 4)
        ma_mean  = round(sum(r["cc_norm"] or 0     for r in model_recs) / n, 4)
        cqs      = round(0.25 * fc_mean + 0.25 * cr_mean +
                         0.25 * ef_mean + 0.25 * ma_mean, 4)

        # Sensitivity analysis: vary weights 10%–55% in 15pp steps
        sa_results = {}
        for dominant_w in [0.10, 0.25, 0.40, 0.55]:
            residual = round((1.0 - dominant_w) / 3, 6)
            for dominant_dim, dim_label in [
                ("fc",  "FC_dominant"),
                ("cr",  "CR_dominant"),
                ("ef",  "EF_dominant"),
                ("ma",  "MA_dominant"),
            ]:
                weights = {"fc": residual, "cr": residual,
                           "ef": residual, "ma": residual}
                weights[dominant_dim] = dominant_w
                sa_cqs = round(
                    weights["fc"] * fc_mean +
                    weights["cr"] * cr_mean +
                    weights["ef"] * ef_mean +
                    weights["ma"] * ma_mean, 4
                )
                sa_results[f"sa_{dim_label}_{int(dominant_w*100)}pct"] = sa_cqs

        row = {
            "model":         model,
            "fc_mean_norm":  fc_mean,
            "cr_mean_norm":  cr_mean,
            "ef_mean_norm":  ef_mean,
            "ma_mean_norm":  ma_mean,
            "cqs_equal_25":  cqs,
        }
        row.update(sa_results)
        cqs_rows.append(row)

    cqs_fieldnames = list(cqs_rows[0].keys())
    with open(CQS_CSV, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=cqs_fieldnames)
        writer.writeheader()
        writer.writerows(cqs_rows)

    print(f"[✓] CQS results written → {CQS_CSV}")
    print("\n── Composite Quality Scores (Equal 25% Weighting) ──")
    for row in cqs_rows:
        print(f"  {row['model']:20s}  CQS = {row['cqs_equal_25']:.4f}  "
              f"(FC={row['fc_mean_norm']:.3f}  "
              f"CR={row['cr_mean_norm']:.3f}  "
              f"EF={row['ef_mean_norm']:.3f}  "
              f"MA={row['ma_mean_norm']:.3f})")
    print("\nDone.")


if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="AI Code Quality Evaluation Pipeline")
    parser.add_argument("--verbose", action="store_true",
                        help="Print per-test details")
    args = parser.parse_args()
    main(verbose=args.verbose)
